advanced.BuiltInWithSelectDynamicData:
// JavaScript
import '@maersk-global/mds-components-core/mc-table';
import data from 'data.json';

const fullDataset = data;
const totalRecords = fullDataset.length;
let pageSize = 10;
let isLoadingPage = false;
const initData = fullDataset.slice(0, 10);

// Simulate server-side API call
const simulateServerFetch = (page: number, pageSize: number): Promise<typeof fullDataset> => {
  return new Promise((resolve) => {
    // Simulate network delay (1000ms)
    setTimeout(() => {
      const startIndex = (page - 1) * pageSize;
      const endIndex = startIndex + pageSize;
      const pageData = fullDataset.slice(startIndex, endIndex);
      resolve(pageData);
    }, 1000);
  });
};

// Handle data fetching
const getData = async (page: number, pageSize: number) => {
  const table = document.querySelector('mc-table');

  // Reset to first page on page size change
  if (!table || isLoadingPage) {
    return;
  }
  isLoadingPage = true;
  table.paginationloading = isLoadingPage;

  try {
    const newData = await simulateServerFetch(page, pageSize);
    table.data = newData;
  } catch (error) {
    console.error('Failed to fetch page data:', error);
  } finally {
    isLoadingPage = false;
    table.paginationloading = isLoadingPage;
  }
};

// Handle page change event
const handlePageChange = async (e: CustomEvent<number>) => {
  const newPage = e.detail;
  await getData(newPage, pageSize);
};

// Handle page size change event
const handlePageSizeChange = async (e: CustomEvent<number>) => {
  pageSize = e.detail;
  await getData(1, pageSize);
};

// Setup
async function setupTable() {
  const table = document.querySelector('mc-table');

  // Define columns
  table.columns = columns;

  // Load initial page
  table.paginationloading = true;
  const initialData = await fetchPageFromServer(1, pageSize);
  table.data = initialData;
  table.paginationtotalrecords = totalRecords;
  table.paginationloading = false;

  // Listen for page changes
  table.addEventListener('paginationpagechange', handlePageChange);
  table.addEventListener('paginationpagesizechange', handlePageSizeChange);
}

window.addEventListener('DOMContentLoaded', setupTable);

// HTML
<mc-table
  pagination="select"
  paginationmode="dynamic"
></mc-table>

