advanced.HeaderAndColumns:
// JavaScript
import '@maersk-global/mds-components-core-table';
import '@maersk-global/mds-components-core-button';
import '@maersk-global/mds-components-core-popover';
import '@maersk-global/mds-components-core-checkbox-group';
import '@maersk-global/mds-components-core-checkbox';
import '@maersk-global/mds-components-core-multi-select';
import '@maersk-global/mds-components-core-option';
import data from 'data.json';
import { columns } from 'columns.js';

const filters = {
  lengthFilter: ['small', 'medium', 'large'],
  statusFilter: ['On schedule', 'Stalled', 'Delayed', 'Unknown'],
} as {
  lengthFilter: string[];
  statusFilter: string[];
};

const selected = {
  lengthFilter: [...filters.lengthFilter],
  statusFilter: [...filters.statusFilter],
};

let statusManuallyChanged = false;
let lengthManuallyChanged = false;
let internalUpdate = false;

const ALL_LENGTH_COUNT = filters.lengthFilter.length;
const ALL_STATUS_COUNT = filters.statusFilter.length;

// Get all elements in the DOM and assign event listeners and data
const mcTable = document.querySelector('mc-table');
mcTable.data = data;
mcTable.columns = columns;

const mcPopover = document.querySelector('mc-popover');
mcPopover[0].addEventListener('click', (e) => e.stopPropagation());
mcPopover[1].addEventListener('click', (e) => e.stopPropagation());

const mcButton = document.querySelector('mc-button');
mcButton[0].icon = 'funnel';
mcButton[1].icon = 'funnel';

const mcCheckboxGroup = document.querySelector('mc-checkbox-group');
mcCheckboxGroup.value = filters.lengthFilter;
mcCheckboxGroup.addEventListener('change', (e) => onLengthChange(e));

const mcMultiSelect = document.querySelector('mc-multi-select');
mcMultiSelect.value = filters.statusFilter;
mcMultiSelect.addEventListener('optionselected', (e) => onStatusSelect(e));

const lengthMatches = (lengthValue, categories) => {
  if (categories.length === 0 || categories.length === ALL_LENGTH_COUNT) return true;
  for (const cat of categories) {
    if (cat === 'small' && lengthValue < 200) return true;
    if (cat === 'medium' && lengthValue > 200 && lengthValue < 301) return true;
    if (cat === 'large' && lengthValue > 300) return true;
  }
  return false;
};

const statusMatches = (status, statuses) => {
  if (statuses.length === 0 || statuses.length === ALL_STATUS_COUNT) return true;
  return statuses.includes(status);
};

const recomputeIcons = () => {
  mcButton[0].icon = selected.lengthFilter.length > 0 && selected.lengthFilter.length < ALL_LENGTH_COUNT ? 'funnel-solid' : 'funnel';
  mcButton[1].icon = selected.statusFilter.length > 0 && selected.statusFilter.length < ALL_STATUS_COUNT ? 'funnel-solid' : 'funnel';
};

const applyCombinedFilter = () => {
  const noLengthFilter = selected.lengthFilter.length === 0 || selected.lengthFilter.length === ALL_LENGTH_COUNT;
  const noStatusFilter = selected.statusFilter.length === 0 || selected.statusFilter.length === ALL_STATUS_COUNT;

  let workingData = data;

  if (!(noLengthFilter && noStatusFilter)) {
    workingData = data.filter(
      (row) => lengthMatches(row.length, selected.lengthFilter) && statusMatches(row.status, selected.statusFilter),
    );
  }

  if (!statusManuallyChanged) {
    const statusesInData = Array.from(new Set(workingData.map((r) => r.status)));
    internalUpdate = true;
    selected.statusFilter = statusesInData;
    mcMultiSelect.value = selected.statusFilter;
    internalUpdate = false;
  }

  if (!lengthManuallyChanged) {
    const order = ['small', 'medium', 'large'];
    const lengthCatsInData = new Set<string>();
    workingData.forEach((r) => {
      if (r.length < 200) lengthCatsInData.add('small');
      else if (r.length > 200 && r.length < 301) lengthCatsInData.add('medium');
      else if (r.length > 300) lengthCatsInData.add('large');
    });
    internalUpdate = true;
    selected.lengthFilter = order.filter((c) => lengthCatsInData.has(c));
    mcCheckboxGroup.value = selected.lengthFilter;
    internalUpdate = false;
  }

  mcTable.data = workingData;
  recomputeIcons();
};

const onLengthChange = (event) => {
  if (internalUpdate) return;
  lengthManuallyChanged = true;
  selected.lengthFilter = event.detail;
  applyCombinedFilter();
};

const onStatusSelect = (event) => {
  if (internalUpdate) return;
  statusManuallyChanged = true;
  selected.statusFilter = event.detail.map((item) => {
    return item.value;
  });
  applyCombinedFilter();
};

// HTML
<mc-table headersticky select selectsticky height="200px">
  <div slot="length_header" class="filter">
    <span>Length (m)</span>
    <mc-popover position="right-top" trigger="click">
      <mc-button
        appearance="neutral"
        fit="small"
        hiddenlabel
        label="Show menu"
        padding="compact"
        slot="trigger"
        variant="plain"
      ></mc-button>
      <div class="popup">
        <mc-checkbox-group
          fit="small"
          legend="Containers"
          orientation="vertical"
          hiddenlegend
        >
          <mc-checkbox fit="small" label="Large (> 300m)" value="large"></mc-checkbox>
          <mc-checkbox fit="small" label="Medium (200m - 300m)" value="medium"></mc-checkbox>
          <mc-checkbox fit="small" label="Small (< 200m)" value="small"></mc-checkbox>
        </mc-checkbox-group>
      </div>
    </mc-popover>
  </div>
  <span slot="status_header" class="filter">
    <span>Status</span>
    <mc-popover position="right-top" trigger="click">
      <mc-button
        appearance="neutral"
        fit="small"
        hiddenlabel
        label="Show menu"
        padding="compact"
        slot="trigger"
        variant="plain"
      ></mc-button>
      <div class="popup" style="z-index: revert-layer;">
        <mc-multi-select
          hiddenlabel
          clearbutton
          fit="small"
          placeholder="Click to select"
        >
          <mc-option value="On schedule">On schedule</mc-option>
          <mc-option value="Stalled">Stalled</mc-option>
          <mc-option value="Delayed">Delayed</mc-option>
          <mc-option value="Unknown">Unknown</mc-option>
        </mc-multi-select>
      </div>
    </mc-popover>
  </span>
</mc-table>

