export interface IMcTable {

Labels object for customizing component text.
If not provided, labels are automatically loaded based on document's lang attribute.

    labels?: Partial<IMcTableLabels>;

An array of objects containing the data to be rendered by the table.
@example
      [
        {
          "id": 1,
          "name": "Madrid Maersk",
          "type": "Container ship",
          "built": "2017",
          "length": 399,
        },
        {
          "id": 2,
          "name": "Mary Maersk",
          "type": "Container ship",
          "built": "2013",
          "length": 399,
        }
      ]

@default []

    data: TableData;

Configuration for cells that should span multiple rows and/or columns.
Each object in the array specifies which cell should span and how many rows/columns.
@example
[
  {
    cellKey: "3_name", // Format: "{rowId}_{columnId}"
    rowspan: 2,
    colspan: 3
  }
]

    spans?: SpanConfig[];

Enable column resizing functionality
@default false

    columnresize?: boolean;

An array of `TableColumn` configurations which informs the table how to render a column and it's data cells.
If no columns are passed, the table will infer columns from the first row of data
@example
      [
        {
          id: 'name',
          label: 'Name',
        },
         {
          id: 'capacity',
          label: 'Capacity (TEU)',
          align: 'right',
        },
      ]


    columns: TableColumn[];

Fit of the table
@default 'medium'

    fit?: Fit;

Default sort column.
Will default to the first column.

    sortdefaultcolumnid?: string;

Default sort direction
@default ascending

    sortdefaultdirection?: TableSortDirection;

Sorting disabled
@default false

    sortdisabled?: boolean;

Enables manual sorting for the table. If this is true, you will be expected to sort your data before it is passed to the table. This is useful if you are doing server-side sorting.
@default false

    sortmanual?: boolean;

Enable integrated pagination controls below the table
@default none

    pagination?: TablePagination;

Pagination mode (static or dynamic), to be used when pagination is enabled
Use 'static' when you pass the whole dataset to the table, and want to use client-side pagination built into the component
Use 'dynamic' when you want to get data set from the server, and call your rest API on each 'pagechange' event.
@default 'static'

    paginationmode?: TablePaginationMode;

Scrolls the table to top left after page change.
@default false

